mapper.update:
update teacher
name = #{name}, gender = #{gender}, college_id = #{collegeId}, title = #{title}, phone = #{phone}, email = #{email}, status = #{status}, account_status = #{accountStatus},
where id = #{id}

mapper.select:
select t.id, t.teacher_no, t.name, t.gender, c.college_name, t.title,
t.status, t.account_status, t.create_time
from teacher t
left join college c on t.college_id = c.id

    t.teacher_no like CONCAT('%', #{teacherNo}, '%')
    t.name like CONCAT('%', #{name}, '%')
    t.gender = #{gender}
    t.college_id = #{collegeId}
    t.status = #{status}
    t.account_status = #{accountStatus}


order by t.create_time desc
